const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'math-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

if (message.length > 10000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 10000 символов)'}}];
}

return [{json: {valid: 1, message: message, session_id: session_id}}];

const message = $('Агрегация').first().json.message;
const historyContext = $('Агрегация').first().json.historyContext || '';
const session_id = $('Агрегация').first().json.session_id || 'math-default';
const lower = message.toLowerCase();

const mathKeywords = [
  'посчитай', 'вычисли', 'вычислить', 'рассчитай', 'рассчитать',
  'реши', 'решить', 'решение', 'уравнен', 'неравенств',
  'формул', 'процент', 'корень', 'степен', 'логарифм',
  'сумм', 'разност', 'произведен', 'делен', 'остаток от',
  'площад', 'объём', 'объем', 'периметр', 'окружност',
  'треугольник', 'квадрат', 'куб', 'прямоугольник', 'цилиндр', 'сфер',
  'интеграл', 'производн', 'предел', 'синус', 'косинус', 'тангенс',
  'матриц', 'вектор', 'определител', 'детерминант',
  'график', 'функци', 'парабол',
  'статистик', 'среднее', 'медиан', 'дисперс', 'отклонен',
  'вероятност', 'комбинатор', 'факториал', 'перестанов', 'сочетан',
  'npv', 'irr', 'roi', 'аннуитет', 'ипотек', 'кредит', 'депозит',
  'инвестиц', 'маржа', 'наценк', 'скидк', 'ндс', 'налог',
  'зарплат', 'рентабельн', 'прибыл', 'выручк', 'себестоимост',
  'сколько будет', 'чему равн', 'найди', 'найти',
  'sqrt', 'calculate', 'solve', 'equation', 'math',
  'конвертируй', 'переведи в'
];

const hasMathExpression = /\d+\s*[+\-*/^%=]\s*\d+/.test(message);
const hasNumbers = /\d{2,}/.test(message) || /\d+[.,]\d+/.test(message);

let isMath = hasMathExpression;

if (!isMath) {
  for (const kw of mathKeywords) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath && hasNumbers && message.length > 20) {
  const taskIndicators = ['сколько', 'какой', 'какая', 'какое', 'найди', 'найти',
    'определи', 'определить', 'если', 'при', 'дано', 'равно', 'равна'];
  for (const kw of taskIndicators) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath && /^[\d\s+\-*/^().,]+$/.test(message.trim())) {
  isMath = true;
}

if (!isMath) {
  return [{ json: { message, mode: 'general', historyContext, session_id } }];
}

return [{ json: { message, mode: 'math', historyContext, session_id } }];

