try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{ json: { success: 0, code: '', error: 'GigaChat недоступен. Попробуйте позже.' } }];
  }

  let code = raw.output[0].content[0].text;

  // Убираем markdown-обёртки
  code = code.replace(/```python\s*/gi, '').replace(/```\s*/g, '').trim();

  // Убираем текст до первого import или первой переменной
  const lines = code.split('\n');
  let startIdx = 0;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.startsWith('import ') || line.startsWith('from ') ||
        line.match(/^[a-zA-Z_]/) || line.startsWith('#') ||
        line.startsWith('print(')) {
      startIdx = i;
      break;
    }
  }
  code = lines.slice(startIdx).join('\n').trim();

  if (!code || code.length < 5) {
    return [{ json: { success: 0, code: '', error: 'GigaChat не смог сгенерировать код.' } }];
  }

  // ПРОВЕРКА БЕЗОПАСНОСТИ
  const dangerous = [
    'import os', 'import sys', 'import subprocess', 'import shutil',
    'import pathlib', 'import socket', 'import http', 'import requests',
    'import urllib', 'import ftplib', 'import smtplib', 'import pickle',
    'open(', 'exec(', 'eval(', '__import__', 'compile(',
    'globals(', 'locals(', 'getattr(', 'setattr(', 'delattr(',
    'os.', 'sys.', 'subprocess.', 'shutil.', 'pathlib.',
    'socket.', 'http.', 'requests.', 'input('
  ];

  const codeLower = code.toLowerCase();
  for (const d of dangerous) {
    if (codeLower.includes(d.toLowerCase())) {
      return [{ json: { success: 0, code: code, error: 'Код содержит запрещённую операцию: ' + d } }];
    }
  }

  if (!code.includes('print(') && !code.includes('print (')) {
    code += '\nprint(result)';
  }

  return [{ json: { success: 1, code: code, error: '' } }];

} catch (e) {
  return [{ json: { success: 0, code: '', error: 'Ошибка обработки ответа GigaChat: ' + e.message } }];
}

const code = $json.code;

try {
  let jsCode = code;

  jsCode = jsCode.replace(/^import .*$/gm, '');
  jsCode = jsCode.replace(/^from .* import .*$/gm, '');

  jsCode = jsCode.replace(/math\.pi/g, 'Math.PI');
  jsCode = jsCode.replace(/math\.e\b/g, 'Math.E');
  jsCode = jsCode.replace(/math\.sqrt\(/g, 'Math.sqrt(');
  jsCode = jsCode.replace(/math\.pow\(/g, 'Math.pow(');
  jsCode = jsCode.replace(/math\.log\(/g, 'Math.log(');
  jsCode = jsCode.replace(/math\.log10\(/g, 'Math.log10(');
  jsCode = jsCode.replace(/math\.log2\(/g, 'Math.log2(');
  jsCode = jsCode.replace(/math\.sin\(/g, 'Math.sin(');
  jsCode = jsCode.replace(/math\.cos\(/g, 'Math.cos(');
  jsCode = jsCode.replace(/math\.tan\(/g, 'Math.tan(');
  jsCode = jsCode.replace(/math\.asin\(/g, 'Math.asin(');
  jsCode = jsCode.replace(/math\.acos\(/g, 'Math.acos(');
  jsCode = jsCode.replace(/math\.atan\(/g, 'Math.atan(');
  jsCode = jsCode.replace(/math\.ceil\(/g, 'Math.ceil(');
  jsCode = jsCode.replace(/math\.floor\(/g, 'Math.floor(');
  jsCode = jsCode.replace(/math\.abs\(/g, 'Math.abs(');
  jsCode = jsCode.replace(/abs\(/g, 'Math.abs(');
  jsCode = jsCode.replace(/math\.factorial\((\w+)\)/g, '(function f(n){let r=1;for(let i=2;i<=n;i++)r*=i;return r})($1)');
  jsCode = jsCode.replace(/math\.radians\(([^)]+)\)/g, '(($1) * Math.PI / 180)');
  jsCode = jsCode.replace(/math\.degrees\(([^)]+)\)/g, '(($1) * 180 / Math.PI)');

  jsCode = jsCode.replace(/f'([^']*)'/g, function(match, content) {
    return '`' + content.replace(/\{([^}]+)\}/g, '${$1}') + '`';
  });
  jsCode = jsCode.replace(/f"([^"]*)"/g, function(match, content) {
    return '`' + content.replace(/\{([^}]+)\}/g, '${$1}') + '`';
  });

  const outputs = [];
  const fakePrint = function() {
    const args = Array.from(arguments);
    outputs.push(args.map(a => typeof a === 'object' ? JSON.stringify(a) : String(a)).join(' '));
  };
  jsCode = jsCode.replace(/\bprint\s*\(/g, 'fakePrint(');

  jsCode = jsCode.replace(/\bTrue\b/g, 'true');
  jsCode = jsCode.replace(/\bFalse\b/g, 'false');
  jsCode = jsCode.replace(/\bNone\b/g, 'null');
  jsCode = jsCode.replace(/\belif\b/g, 'else if');
  jsCode = jsCode.replace(/len\(([^)]+)\)/g, '$1.length');

  jsCode = jsCode.replace(/for\s+(\w+)\s+in\s+range\(([^,]+),\s*([^)]+)\)/g,
    'for (let $1 = $2; $1 < $3; $1++)');
  jsCode = jsCode.replace(/for\s+(\w+)\s+in\s+range\(([^)]+)\)/g,
    'for (let $1 = 0; $1 < $2; $1++)');

  jsCode = jsCode.replace(/statistics\.mean\(([^)]+)\)/g, '(($1).reduce((a,b)=>a+b,0)/($1).length)');
  jsCode = jsCode.replace(/statistics\.median\(([^)]+)\)/g, '(function(arr){const s=[...arr].sort((a,b)=>a-b);const m=Math.floor(s.length/2);return s.length%2?s[m]:(s[m-1]+s[m])/2})($1)');
  jsCode = jsCode.replace(/statistics\.stdev\(([^)]+)\)/g, '(function(arr){const m=arr.reduce((a,b)=>a+b,0)/arr.length;return Math.sqrt(arr.reduce((s,v)=>s+(v-m)**2,0)/(arr.length-1))})($1)');
  jsCode = jsCode.replace(/statistics\.variance\(([^)]+)\)/g, '(function(arr){const m=arr.reduce((a,b)=>a+b,0)/arr.length;return arr.reduce((s,v)=>s+(v-m)**2,0)/(arr.length-1)})($1)');
  jsCode = jsCode.replace(/sum\(([^)]+)\)/g, '($1).reduce((a,b)=>a+b,0)');
  jsCode = jsCode.replace(/max\(([^)]+)\)/g, 'Math.max(...$1)');
  jsCode = jsCode.replace(/min\(([^)]+)\)/g, 'Math.min(...$1)');

  const finalLines = jsCode.split('\n');
  let processed = [];
  let indentStack = [0];

  for (let i = 0; i < finalLines.length; i++) {
    let line = finalLines[i];
    const trimmed = line.trim();
    if (!trimmed) continue;

    const indent = line.search(/\S/);
    if (indent < 0) continue;

    while (indentStack.length > 1 && indent < indentStack[indentStack.length - 1]) {
      indentStack.pop();
      processed.push(' '.repeat(indentStack[indentStack.length - 1]) + '}');
    }

    if (trimmed.endsWith(':')) {
      line = line.replace(/:$/, ' {');
    }

    processed.push(line);

    if (line.trim().endsWith('{')) {
      indentStack.push(indent + 4);
    }
  }

  while (indentStack.length > 1) {
    indentStack.pop();
    processed.push('}');
  }

  jsCode = processed.join('\n');

  const fn = new Function('fakePrint', 'Math', jsCode);
  fn(fakePrint, Math);

  const result = outputs.join('\n');

  if (!result || result.trim().length === 0) {
    return [{ json: { computed: false, result: '', final_line: '', code: code, error: 'Код выполнился, но не вернул результат.' } }];
  }

  // Извлекаем финальную строку (последняя непустая) — она и есть ответ для пользователя.
  // Это число берётся в "Проверка ответа" детерминированно, без посредничества LLM.
  const trimmedLines = outputs.map(l => String(l).trim()).filter(l => l.length > 0);
  const finalLine = trimmedLines.length > 0 ? trimmedLines[trimmedLines.length - 1] : result.trim();

  return [{ json: { computed: true, result: result, final_line: finalLine, code: code, error: '' } }];

} catch (e) {
  return [{ json: { computed: false, result: '', final_line: '', code: code, error: 'Ошибка вычисления: ' + e.message } }];
}

