// Собираем итоговый ответ детерминированно:
// число — из вывода Python (final_line), пояснение — от LLM.
// Это предотвращает ошибку, когда LLM подсовывает промежуточное значение.
try {
  const raw = $input.first().json;
  const prev = $('Выполнить код').first().json;

  // Если вычисление сломалось — fallback
  if (!prev || !prev.computed) {
    if (prev && prev.error) {
      return [{ json: { response_text: 'Не удалось решить задачу: ' + prev.error } }];
    }
    return [{ json: { response_text: 'Не удалось обработать задачу.' } }];
  }

  const finalLine = (prev.final_line || prev.result || '').trim();
  if (!finalLine) {
    return [{ json: { response_text: 'Код выполнился, но не вернул значение.' } }];
  }

  // Извлекаем пояснение LLM
  let explanation = '';
  try {
    explanation = raw.output[0].content[0].text.trim();
  } catch (e) {
    explanation = '';
  }

  // Защита: если LLM всё-таки начала с "Ответ: ..." — срезаем эту шапку,
  // чтобы не было дубликата числа в финальном ответе.
  explanation = explanation
    .replace(/^Ответ\s*[:\-]\s*[^\n.]+[.\n]\s*/i, '')
    .replace(/^Итак[,]?\s*получаем[^\n.]+[.\n]\s*/i, '')
    .trim();

  // Финальный текст: число всегда из Python, объяснение от LLM (или пустое)
  let response = 'Ответ: ' + finalLine;
  if (explanation) {
    response += '\n\n' + explanation;
  }

  return [{ json: { response_text: response } }];
} catch(e) {
  const prev = $('Выполнить код').first().json;
  if (prev && prev.final_line) {
    return [{ json: { response_text: 'Ответ: ' + prev.final_line } }];
  }
  if (prev && prev.result) {
    return [{ json: { response_text: 'Ответ: ' + prev.result } }];
  }
  return [{ json: { response_text: 'Ошибка обработки.' } }];
}

